from abc import ABC, abstractmethod
from typing import Callable, Tuple, Dict, Any, Optional, List
from dataclasses import dataclass, field
import numpy as np
from scipy.optimize import minimize

@dataclass
class StrategyConfig:
    learning_rate: float = 0.1
    max_iterations: int = 100
    tolerance: float = 1e-6
    custom_params: Dict[str, Any] = field(default_factory=dict)

class OptimizationStrategy(ABC):
    def __init__(self, config: StrategyConfig):
        self.config = config

    @abstractmethod
    def optimize(
        self,
        objective: Callable[[np.ndarray], float],
        initial_params: np.ndarray
    ) -> Tuple[np.ndarray, float, Dict[str, Any]]:
        pass

    @abstractmethod
    def get_name(self) -> str:
        pass

    @abstractmethod
    def requires_gradients(self) -> bool:
        pass

class GradientDescentStrategy(OptimizationStrategy):
    def optimize(
        self,
        objective: Callable[[np.ndarray], float],
        initial_params: np.ndarray
    ) -> Tuple[np.ndarray, float, Dict[str, Any]]:
        params = initial_params.copy()
        history = []
        epsilon = 1e-5

        for i in range(self.config.max_iterations):
            value = objective(params)
            history.append(value)

            grad = np.zeros_like(params)
            for j in range(len(params)):
                params_plus = params.copy()
                params_plus[j] += epsilon
                grad[j] = (objective(params_plus) - value) / epsilon

            params = params - self.config.learning_rate * grad

            if len(history) > 1 and abs(history[-1] - history[-2]) < self.config.tolerance:
                break

        return params, objective(params), {"iterations": i + 1, "history": history}

    def get_name(self) -> str:
        return "GradientDescent"

    def requires_gradients(self) -> bool:
        return True

class COBYLAStrategy(OptimizationStrategy):
    def optimize(
        self,
        objective: Callable[[np.ndarray], float],
        initial_params: np.ndarray
    ) -> Tuple[np.ndarray, float, Dict[str, Any]]:
        history = []

        def tracked_objective(params):
            val = objective(params)
            history.append(val)
            return val

        result = minimize(
            tracked_objective,
            initial_params,
            method='COBYLA',
            options={
                'maxiter': self.config.max_iterations,
                'rhobeg': self.config.custom_params.get('rhobeg', 0.5)
            }
        )

        return result.x, result.fun, {"iterations": result.nfev, "history": history, "success": result.success}

    def get_name(self) -> str:
        return "COBYLA"

    def requires_gradients(self) -> bool:
        return False

class SPSAStrategy(OptimizationStrategy):
    def optimize(
        self,
        objective: Callable[[np.ndarray], float],
        initial_params: np.ndarray
    ) -> Tuple[np.ndarray, float, Dict[str, Any]]:
        params = initial_params.copy()
        history = []
        c = self.config.custom_params.get('perturbation', 0.1)
        a = self.config.learning_rate

        for k in range(self.config.max_iterations):
            ak = a / (k + 1) ** 0.602
            ck = c / (k + 1) ** 0.101

            delta = np.random.choice([-1, 1], size=len(params))

            y_plus = objective(params + ck * delta)
            y_minus = objective(params - ck * delta)

            ghat = (y_plus - y_minus) / (2 * ck * delta)
            params = params - ak * ghat

            history.append((y_plus + y_minus) / 2)

        final_value = objective(params)
        return params, final_value, {"iterations": self.config.max_iterations, "history": history}

    def get_name(self) -> str:
        return "SPSA"

    def requires_gradients(self) -> bool:
        return False

class OptimizerContext:
    def __init__(self, strategy: OptimizationStrategy):
        self._strategy = strategy

    def set_strategy(self, strategy: OptimizationStrategy):
        self._strategy = strategy

    def optimize(self, objective: Callable, initial_params: np.ndarray) -> Dict[str, Any]:
        params, value, metadata = self._strategy.optimize(objective, initial_params)
        return {
            "optimizer": self._strategy.get_name(),
            "optimal_params": params,
            "optimal_value": value,
            **metadata
        }

def select_strategy(
    has_gradients: bool,
    num_parameters: int,
    noisy_objective: bool
) -> OptimizationStrategy:
    config = StrategyConfig()

    if noisy_objective:
        config.custom_params['perturbation'] = 0.2
        return SPSAStrategy(config)
    elif has_gradients and num_parameters < 20:
        return GradientDescentStrategy(config)
    else:
        return COBYLAStrategy(config)
